package com.example.woofie.data
import com.example.woofie.model.Profession import com.example.woofie.model.QuizQuestion import com.example.woofie.model.UserProfile
object WoofieRepository { data class LessonStage( val number: Int, val title: String, val lessonRange: IntRange )
data class LessonOutcome( val correctAnswers: Int, val totalQuestions: Int, val earnedXp: Int, val passed: Boolean ) { val scoreLabel: String = "$correctAnswers/$totalQuestions" }
const val LESSON_SIZE = 8 const val MIN_CORRECT_TO_PASS = 6
var profile: UserProfile? = null var lastResultLabel: String? = null var lastEarnedXp: Int = 0 var lastLessonPassed: Boolean = false val recentMistakes: MutableList<String> = mutableListOf()
fun getLessonStages(profession: Profession): List<LessonStage> { return when (profession) { Profession.IT -> listOf( LessonStage(1, "Entorno IT y componentes fisicos", 1..2), LessonStage(2, "Hardware en el trabajo", 3..4), LessonStage(3, "Redes y soporte tecnico", 5..6), LessonStage(4, "Frontend y colaboracion agil", 7..8) )
Profession.HEALTH -> listOf( LessonStage(1, "Comunicacion con pacientes", 1..2), LessonStage(2, "Signos vitales y seguimiento", 3..4), LessonStage(3, "Indicaciones y medicacion", 5..6), LessonStage(4, "Alta y coordinacion clinica", 7..8) )
Profession.SALES -> listOf( LessonStage(1, "Prospeccion y contexto comercial", 1..2), LessonStage(2, "Discovery y necesidades", 3..4), LessonStage(3, "Objecciones y propuesta", 5..6), LessonStage(4, "Cierre y seguimiento", 7..8) ) } }
fun getTotalLessons(profession: Profession): Int { return getLessonStages(profession).sumOf { stage -> stage.lessonRange.count() } }
fun getQuestionsFor(profession: Profession): List<QuizQuestion> { return when (profession) { Profession.IT -> listOf( QuizQuestion( prompt = "How do you say 'ticket resuelto' in a sprint update?", options = listOf("Solved ticket", "Strong ticket", "Ticket weather"), correctIndex = 0 ), QuizQuestion( prompt = "Choose the best phrase for daily standup:", options = listOf("I blocked yesterday", "I am blocked by API", "I was coding table"), correctIndex = 1 ), QuizQuestion( prompt = "What means 'deployment completed successfully'?", options = listOf("La reunion fue cancelada", "El despliegue termino bien", "No hay conexion"), correctIndex = 1 ), QuizQuestion( prompt = "Translate: 'Necesito revisar los logs del servidor'.", options = listOf("I need to review the server logs", "I need to paint the server", "I need to close the office"), correctIndex = 0 ), QuizQuestion( prompt = "Best phrase for code review request:", options = listOf("Could you review this pull request?", "Could you remove this keyboard?", "Could you call my manager now?"), correctIndex = 0 ), QuizQuestion( prompt = "What means 'rollback to previous version'?", options = listOf("Avanzar a la siguiente version", "Volver a la version anterior", "Eliminar el proyecto"), correctIndex = 1 ), QuizQuestion( prompt = "Translate: 'La API responde con timeout'.", options = listOf("The API responds with a timeout", "The API responds with a smile", "The API responds with a shortcut"), correctIndex = 0 ), QuizQuestion( prompt = "Best sentence for sprint planning:", options = listOf("Let's estimate these tasks", "Let's cancel all tasks", "Let's ship without tests"), correctIndex = 0 ) )
Profession.HEALTH -> listOf( QuizQuestion( prompt = "Translate: 'Tome este medicamento dos veces al dia'", options = listOf( "Take this medicine twice a day", "Drink this medicine all week", "Call this medicine now" ), correctIndex = 0 ), QuizQuestion( prompt = "Best phrase to ask patient comfort:", options = listOf("Are you feeling comfortable?", "You are fine now?", "Can you sleep medicine?"), correctIndex = 0 ), QuizQuestion( prompt = "What means 'follow-up appointment'?", options = listOf("Cita de seguimiento", "Cita urgente", "Examen de sangre"), correctIndex = 0 ), QuizQuestion( prompt = "Translate: 'Respire profundo, todo esta bajo control'.", options = listOf("Breathe deeply, everything is under control", "Run quickly, nothing is ready", "Drink this later"), correctIndex = 0 ), QuizQuestion( prompt = "Best phrase before checking vital signs:", options = listOf("I will check your vital signs", "I will cancel your room", "I will call your office"), correctIndex = 0 ), QuizQuestion( prompt = "Translate: 'Debe guardar reposo por tres dias'.", options = listOf("You should rest for three days", "You should walk for three hours", "You should skip your meal"), correctIndex = 0 ), QuizQuestion( prompt = "What means 'discharge instructions'?", options = listOf("Instrucciones de alta", "Instrucciones de ingreso", "Resultado de radiografia"), correctIndex = 0 ), QuizQuestion( prompt = "Best phrase for pain scale question:", options = listOf("How would you rate your pain from 1 to 10?", "Can you pay now?", "Do you need a new room key?"), correctIndex = 0 ) )
Profession.SALES -> listOf( QuizQuestion( prompt = "Translate: 'Podemos agendar una llamada de seguimiento'", options = listOf( "Can we schedule a follow-up call?", "Can we close now?", "Can we buy this later?" ), correctIndex = 0 ), QuizQuestion( prompt = "Choose the best sentence for objection handling:", options = listOf("I understand your concern", "You are wrong", "This is impossible"), correctIndex = 0 ), QuizQuestion( prompt = "What means 'pricing proposal attached'?", options = listOf("Propuesta de precios adjunta", "Cliente no responde", "Producto agotado"), correctIndex = 0 ), QuizQuestion( prompt = "Translate: 'Gracias por tu tiempo en la reunion'.", options = listOf("Thank you for your time in the meeting", "You are late for the meeting", "Let's stop this forever"), correctIndex = 0 ), QuizQuestion( prompt = "Best opening for discovery call:", options = listOf("Can you tell me about your current process?", "Can you buy now in one minute?", "Can you send money first?"), correctIndex = 0 ), QuizQuestion( prompt = "Translate: 'Te envio un resumen por correo'.", options = listOf("I will send you a summary by email", "I will send you a car by noon", "I will send you a voice note to HR"), correctIndex = 0 ), QuizQuestion( prompt = "What means 'decision-maker'?", options = listOf("Persona que toma la decision", "Persona que guarda facturas", "Persona que recibe paquetes"), correctIndex = 0 ), QuizQuestion( prompt = "Best phrase to schedule next step:", options = listOf("Does next Tuesday work for a demo?", "Do you want to cancel all meetings?", "Can you transfer now?"), correctIndex = 0 ) ) } }
fun registerLessonResult(correctAnswers: Int, totalAnswers: Int = LESSON_SIZE): LessonOutcome { val currentProfile = profile ?: return LessonOutcome( correctAnswers = correctAnswers, totalQuestions = totalAnswers, earnedXp = 0, passed = false )
val passedLesson = correctAnswers >= MIN_CORRECT_TO_PASS val earnedXp = (correctAnswers * 12) + if (passedLesson) 40 else 10
currentProfile.completedLessons += 1 currentProfile.xp += earnedXp currentProfile.streak += 1 lastResultLabel = "$correctAnswers/$totalAnswers" lastEarnedXp = earnedXp lastLessonPassed = passedLesson
return LessonOutcome( correctAnswers = correctAnswers, totalQuestions = totalAnswers, earnedXp = earnedXp, passed = passedLesson ) } }

package com.example.woofie.ui

import android.annotation.SuppressLint
import android.animation.ObjectAnimator
import android.animation.ValueAnimator
import android.content.Context
import android.os.Bundle
import android.view.MotionEvent
import android.view.LayoutInflater
import android.view.View
import android.view.animation.AnimationUtils
import android.widget.FrameLayout
import android.widget.LinearLayout
import android.widget.TextView
import androidx.core.content.ContextCompat
import androidx.fragment.app.Fragment
import com.example.woofie.R
import com.example.woofie.data.WoofieRepository
import com.example.woofie.ui.common.applySystemBarsPadding

class LessonPathFragment : Fragment(R.layout.fragment_lesson_path) {

    interface Listener {
        fun onOpenLessonFromPath()
    }

    private var listener: Listener? = null

    override fun onAttach(context: Context) {
        super.onAttach(context)
        listener = context as? Listener
    }

    override fun onDetach() {
        super.onDetach()
        listener = null
    }

    @SuppressLint("ClickableViewAccessibility")
    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        view.applySystemBarsPadding()
        val profile = WoofieRepository.profile ?: return
        val container: LinearLayout = view.findViewById(R.id.pathContainer)
        val trailContainer: LinearLayout = view.findViewById(R.id.pathTrailContainer)
        val nodeAnim = AnimationUtils.loadAnimation(requireContext(), R.anim.woofie_option_pop)
        container.removeAllViews()
        trailContainer.removeAllViews()

        val stages = WoofieRepository.getLessonStages(profile.profession)
        val totalNodes = WoofieRepository.getTotalLessons(profile.profession)
        val completed = profile.completedLessons.coerceAtMost(totalNodes)
        val nextUnlocked = (completed + 1).coerceAtMost(totalNodes)
        val currentNode = if (nextUnlocked <= totalNodes) nextUnlocked else totalNodes

        fun dp(value: Int): Int = (value * resources.displayMetrics.density).toInt()

        repeat(totalNodes) { index ->
            val number = index + 1
            val isDone = number <= completed
            val isCurrentTrail = number == currentNode

            val chip = TextView(requireContext()).apply {
                text = number.toString()
                textSize = 13f
                setTypeface(typeface, android.graphics.Typeface.BOLD)
                gravity = android.view.Gravity.CENTER
                layoutParams = LinearLayout.LayoutParams(dp(30), dp(30))
                background = when {
                    isDone -> ContextCompat.getDrawable(requireContext(), R.drawable.lesson_node_completed)
                    isCurrentTrail -> ContextCompat.getDrawable(requireContext(), R.drawable.lesson_node_current)
                    else -> ContextCompat.getDrawable(requireContext(), R.drawable.lesson_node_locked)
                }
                setTextColor(
                    if (isDone) ContextCompat.getColor(requireContext(), R.color.woofie_text_on_dark)
                    else ContextCompat.getColor(requireContext(), R.color.woofie_primary_dark)
                )
            }
            trailContainer.addView(chip)

            if (number < totalNodes) {
                val connector = View(requireContext()).apply {
                    layoutParams = LinearLayout.LayoutParams(dp(18), dp(4)).also { params ->
                        params.leftMargin = dp(6)
                        params.rightMargin = dp(6)
                    }
                    setBackgroundColor(
                        ContextCompat.getColor(
                            requireContext(),
                            if (number < currentNode) R.color.woofie_primary else R.color.woofie_gray_200
                        )
                    )
                }
                trailContainer.addView(connector)
            }
        }

        stages.forEach { stage ->
            val stageTitle = TextView(requireContext()).apply {
                text = "Etapa ${stage.number}: ${stage.title}"
                setTextColor(ContextCompat.getColor(requireContext(), R.color.woofie_primary_dark))
                setTypeface(typeface, android.graphics.Typeface.BOLD)
                textSize = 16f
                setPadding(dp(4), dp(10), dp(4), dp(8))
            }
            container.addView(stageTitle)

            stage.lessonRange.forEach { nodeNumber ->
                val index = nodeNumber - 1
                val nodeView = LayoutInflater.from(requireContext())
                    .inflate(R.layout.item_lesson_path_node, container, false)

                val anchor: FrameLayout = nodeView.findViewById(R.id.nodeAnchor)
                val badge: TextView = nodeView.findViewById(R.id.textNodeBadge)
                val connector: View = nodeView.findViewById(R.id.pathConnector)
                val shadow: View = nodeView.findViewById(R.id.nodeShadow)

                val isCompleted = nodeNumber <= completed
                val isUnlocked = nodeNumber <= nextUnlocked
                val isCurrent = nodeNumber == currentNode

                badge.text = nodeNumber.toString()
                badge.background = when {
                    isCompleted -> ContextCompat.getDrawable(requireContext(), R.drawable.lesson_node_completed)
                    isCurrent -> ContextCompat.getDrawable(requireContext(), R.drawable.lesson_node_current)
                    isUnlocked -> ContextCompat.getDrawable(requireContext(), R.drawable.lesson_node_unlocked)
                    else -> ContextCompat.getDrawable(requireContext(), R.drawable.lesson_node_locked)
                }
                badge.setTextColor(
                    if (isCompleted) ContextCompat.getColor(requireContext(), R.color.woofie_text_on_dark)
                    else ContextCompat.getColor(requireContext(), R.color.woofie_primary_dark)
                )
                badge.alpha = if (isUnlocked) 1f else 0.65f
                badge.isEnabled = isUnlocked
                shadow.alpha = if (isUnlocked) 1f else 0.45f
                badge.scaleX = if (isCurrent) 1.08f else 1f
                badge.scaleY = if (isCurrent) 1.08f else 1f

                val anchorParams = anchor.layoutParams as LinearLayout.LayoutParams
                val offsetX = when (index % 6) {
                    0 -> -120f
                    1 -> -26f
                    2 -> 86f
                    3 -> 120f
                    4 -> 18f
                    else -> -92f
                }
                anchor.translationX = offsetX
                anchor.layoutParams = anchorParams

                connector.visibility = if (nodeNumber == totalNodes) View.GONE else View.VISIBLE
                if (nodeNumber < totalNodes) {
                    val nextOffsetX = when ((index + 1) % 6) {
                        0 -> -120f
                        1 -> -26f
                        2 -> 86f
                        3 -> 120f
                        4 -> 18f
                        else -> -92f
                    }
                    connector.translationX = (nextOffsetX - offsetX) / 2f
                    connector.rotation = (nextOffsetX - offsetX) / 10f
                }

                if (isUnlocked) {
                    val floatAnim = ObjectAnimator.ofFloat(badge, View.TRANSLATION_Y, 0f, -8f, 0f).apply {
                        duration = 1800
                        startDelay = index * 100L
                        repeatCount = ValueAnimator.INFINITE
                    }
                    floatAnim.start()

                    badge.setOnTouchListener { touchedView, event ->
                        when (event.actionMasked) {
                            MotionEvent.ACTION_DOWN -> {
                                touchedView.animate().scaleX(0.92f).scaleY(0.92f).setDuration(80).start()
                                true
                            }

                            MotionEvent.ACTION_UP -> {
                                touchedView.animate().scaleX(1f).scaleY(1f).setDuration(120).start()
                                touchedView.performClick()
                                true
                            }

                            MotionEvent.ACTION_CANCEL -> {
                                touchedView.animate().scaleX(1f).scaleY(1f).setDuration(120).start()
                                true
                            }

                            else -> false
                        }
                    }

                    badge.setOnClickListener {
                        it.startAnimation(nodeAnim)
                        listener?.onOpenLessonFromPath()
                    }
                }

                badge.elevation = if (isCurrent) 10f else 6f

                nodeView.startAnimation(nodeAnim)
                container.addView(nodeView)
            }
        }
    }
}

package com.example.woofie.ui

import android.annotation.SuppressLint
import android.animation.ObjectAnimator
import android.animation.ValueAnimator
import android.content.Context
import android.os.Bundle
import android.view.MotionEvent
import android.view.LayoutInflater
import android.view.View
import android.view.animation.AnimationUtils
import android.widget.FrameLayout
import android.widget.LinearLayout
import android.widget.TextView
import androidx.core.content.ContextCompat
import androidx.fragment.app.Fragment
import com.example.woofie.R
import com.example.woofie.data.WoofieRepository
import com.example.woofie.ui.common.applySystemBarsPadding

class LessonPathFragment : Fragment(R.layout.fragment_lesson_path) {

    interface Listener {
        fun onOpenLessonFromPath()
    }

    private var listener: Listener? = null

    override fun onAttach(context: Context) {
        super.onAttach(context)
        listener = context as? Listener
    }

    override fun onDetach() {
        super.onDetach()
        listener = null
    }

    @SuppressLint("ClickableViewAccessibility")
    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        view.applySystemBarsPadding()
        val profile = WoofieRepository.profile ?: return
        val container: LinearLayout = view.findViewById(R.id.pathContainer)
        val trailContainer: LinearLayout = view.findViewById(R.id.pathTrailContainer)
        val nodeAnim = AnimationUtils.loadAnimation(requireContext(), R.anim.woofie_option_pop)
        container.removeAllViews()
        trailContainer.removeAllViews()

        val stages = WoofieRepository.getLessonStages(profile.profession)
        val totalNodes = WoofieRepository.getTotalLessons(profile.profession)
        val completed = profile.completedLessons.coerceAtMost(totalNodes)
        val nextUnlocked = (completed + 1).coerceAtMost(totalNodes)
        val currentNode = if (nextUnlocked <= totalNodes) nextUnlocked else totalNodes

        fun dp(value: Int): Int = (value * resources.displayMetrics.density).toInt()

        repeat(totalNodes) { index ->
            val number = index + 1
            val isDone = number <= completed
            val isCurrentTrail = number == currentNode

            val chip = TextView(requireContext()).apply {
                text = number.toString()
                textSize = 13f
                setTypeface(typeface, android.graphics.Typeface.BOLD)
                gravity = android.view.Gravity.CENTER
                layoutParams = LinearLayout.LayoutParams(dp(30), dp(30))
                background = when {
                    isDone -> ContextCompat.getDrawable(requireContext(), R.drawable.lesson_node_completed)
                    isCurrentTrail -> ContextCompat.getDrawable(requireContext(), R.drawable.lesson_node_current)
                    else -> ContextCompat.getDrawable(requireContext(), R.drawable.lesson_node_locked)
                }
                setTextColor(
                    if (isDone) ContextCompat.getColor(requireContext(), R.color.woofie_text_on_dark)
                    else ContextCompat.getColor(requireContext(), R.color.woofie_primary_dark)
                )
            }
            trailContainer.addView(chip)

            if (number < totalNodes) {
                val connector = View(requireContext()).apply {
                    layoutParams = LinearLayout.LayoutParams(dp(18), dp(4)).also { params ->
                        params.leftMargin = dp(6)
                        params.rightMargin = dp(6)
                    }
                    setBackgroundColor(
                        ContextCompat.getColor(
                            requireContext(),
                            if (number < currentNode) R.color.woofie_primary else R.color.woofie_gray_200
                        )
                    )
                }
                trailContainer.addView(connector)
            }
        }

        stages.forEach { stage ->
            val stageTitle = TextView(requireContext()).apply {
                text = "Etapa ${stage.number}: ${stage.title}"
                setTextColor(ContextCompat.getColor(requireContext(), R.color.woofie_primary_dark))
                setTypeface(typeface, android.graphics.Typeface.BOLD)
                textSize = 16f
                setPadding(dp(4), dp(10), dp(4), dp(8))
            }
            container.addView(stageTitle)

            stage.lessonRange.forEach { nodeNumber ->
                val index = nodeNumber - 1
                val nodeView = LayoutInflater.from(requireContext())
                    .inflate(R.layout.item_lesson_path_node, container, false)

                val anchor: FrameLayout = nodeView.findViewById(R.id.nodeAnchor)
                val badge: TextView = nodeView.findViewById(R.id.textNodeBadge)
                val connector: View = nodeView.findViewById(R.id.pathConnector)
                val shadow: View = nodeView.findViewById(R.id.nodeShadow)
                val concept: TextView = nodeView.findViewById(R.id.textNodeConcept)
                val edgeTop: View = nodeView.findViewById(R.id.edgeTop)
                val edgeRight: View = nodeView.findViewById(R.id.edgeRight)
                val edgeBottom: View = nodeView.findViewById(R.id.edgeBottom)
                val edgeLeft: View = nodeView.findViewById(R.id.edgeLeft)

                val isCompleted = nodeNumber <= completed
                val isUnlocked = nodeNumber <= nextUnlocked
                val isCurrent = nodeNumber == currentNode

                badge.text = nodeNumber.toString()
                concept.text = getString(
                    R.string.lesson_path_concept_format,
                    nodeNumber,
                    stage.title
                )
                concept.alpha = if (isUnlocked) 1f else 0.7f
                badge.background = when {
                    isCompleted -> ContextCompat.getDrawable(requireContext(), R.drawable.lesson_node_completed)
                    isCurrent -> ContextCompat.getDrawable(requireContext(), R.drawable.lesson_node_current)
                    isUnlocked -> ContextCompat.getDrawable(requireContext(), R.drawable.lesson_node_unlocked)
                    else -> ContextCompat.getDrawable(requireContext(), R.drawable.lesson_node_locked)
                }
                badge.setTextColor(
                    if (isCompleted) ContextCompat.getColor(requireContext(), R.color.woofie_text_on_dark)
                    else ContextCompat.getColor(requireContext(), R.color.woofie_primary_dark)
                )
                badge.alpha = if (isUnlocked) 1f else 0.65f
                badge.isEnabled = isUnlocked
                shadow.alpha = if (isUnlocked) 1f else 0.45f
                badge.scaleX = if (isCurrent) 1.08f else 1f
                badge.scaleY = if (isCurrent) 1.08f else 1f

                val edgeColor = if (isCompleted) {
                    ContextCompat.getColor(requireContext(), R.color.woofie_primary)
                } else {
                    ContextCompat.getColor(requireContext(), R.color.woofie_gray_200)
                }
                edgeTop.setBackgroundColor(edgeColor)
                edgeRight.setBackgroundColor(edgeColor)
                edgeBottom.setBackgroundColor(edgeColor)
                edgeLeft.setBackgroundColor(edgeColor)

                val anchorParams = anchor.layoutParams as LinearLayout.LayoutParams
                val offsetX = when (index % 6) {
                    0 -> 0f
                    1 -> 24f
                    2 -> 48f
                    3 -> 72f
                    4 -> 32f
                    else -> 8f
                }
                anchor.translationX = offsetX
                anchor.layoutParams = anchorParams

                connector.visibility = if (nodeNumber == totalNodes) View.GONE else View.VISIBLE
                if (nodeNumber < totalNodes) {
                    connector.translationX = offsetX
                    connector.setBackgroundColor(
                        ContextCompat.getColor(
                            requireContext(),
                            if (nodeNumber < currentNode) R.color.woofie_primary else R.color.woofie_primary_light
                        )
                    )
                }

                if (isUnlocked) {
                    val floatAnim = ObjectAnimator.ofFloat(badge, View.TRANSLATION_Y, 0f, -8f, 0f).apply {
                        duration = 1800
                        startDelay = index * 100L
                        repeatCount = ValueAnimator.INFINITE
                    }
                    floatAnim.start()

                    badge.setOnTouchListener { touchedView, event ->
                        when (event.actionMasked) {
                            MotionEvent.ACTION_DOWN -> {
                                touchedView.animate().scaleX(0.92f).scaleY(0.92f).setDuration(80).start()
                                true
                            }

                            MotionEvent.ACTION_UP -> {
                                touchedView.animate().scaleX(1f).scaleY(1f).setDuration(120).start()
                                touchedView.performClick()
                                true
                            }

                            MotionEvent.ACTION_CANCEL -> {
                                touchedView.animate().scaleX(1f).scaleY(1f).setDuration(120).start()
                                true
                            }

                            else -> false
                        }
                    }

                    badge.setOnClickListener {
                        it.startAnimation(nodeAnim)
                        listener?.onOpenLessonFromPath()
                    }
                }

                badge.elevation = if (isCurrent) 10f else 6f

                nodeView.startAnimation(nodeAnim)
                container.addView(nodeView)
            }
        }
    }
}

package com.example.woofie.ui

import android.content.Context
import android.os.Bundle
import android.view.View
import androidx.core.widget.doOnTextChanged
import androidx.fragment.app.Fragment
import com.example.woofie.R
import com.example.woofie.ui.common.applySystemBarsPadding
import com.google.android.material.button.MaterialButton
import com.google.android.material.textfield.TextInputEditText

class LoginFragment : Fragment(R.layout.fragment_login) {

    interface Listener {
        fun onLoginContinue(email: String)
    }

    private var listener: Listener? = null

    override fun onAttach(context: Context) {
        super.onAttach(context)
        listener = context as? Listener
    }

    override fun onDetach() {
        super.onDetach()
        listener = null
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        view.applySystemBarsPadding()

        val emailInput: TextInputEditText = view.findViewById(R.id.editEmail)
        val buttonContinue: MaterialButton = view.findViewById(R.id.buttonLoginContinue)
        val buttonCreate: MaterialButton = view.findViewById(R.id.buttonCreateAccount)

        fun updateButtonState() {
            val email = emailInput.text?.toString()?.trim().orEmpty()
            buttonContinue.isEnabled = email.isNotBlank()
        }

        emailInput.doOnTextChanged { _, _, _, _ -> updateButtonState() }

        buttonContinue.setOnClickListener {
            val email = emailInput.text?.toString()?.trim().orEmpty()
            if (email.isNotBlank()) {
                listener?.onLoginContinue(email)
            }
        }

        buttonCreate.setOnClickListener {
            val email = emailInput.text?.toString()?.trim().orEmpty()
            listener?.onLoginContinue(email)
        }

        updateButtonState()
    }
}
